const models = [
  { name: 'YOLOv8n', map: 37.3, latency: 1.1, size: 6.2, flops: 8.7, family: 'YOLO' },
  { name: 'YOLOv8s', map: 44.9, latency: 2.0, size: 22.5, flops: 28.6, family: 'YOLO' },
  { name: 'YOLOv8m', map: 50.2, latency: 4.5, size: 52.1, flops: 79.0, family: 'YOLO' },
  { name: 'YOLOv8l', map: 52.9, latency: 8.4, size: 87.7, flops: 165.2, family: 'YOLO' },
  { name: 'YOLOv8x', map: 53.9, latency: 13.5, size: 136.7, flops: 257.8, family: 'YOLO' },
  { name: 'Faster R-CNN (R50)', map: 37.0, latency: 50.0, size: 108.0, flops: 180.0, family: 'Two-Stage' },
  { name: 'SSD (ResNet50)', map: 30.5, latency: 22.0, size: 95.0, flops: 90.0, family: 'Single-Stage' },
  { name: 'EfficientDet-D0', map: 34.6, latency: 10.2, size: 15.0, flops: 2.5, family: 'Scalable' },
  { name: 'EfficientDet-D4', map: 49.7, latency: 45.0, size: 84.0, flops: 34.0, family: 'Scalable' },
  { name: 'DETR-R50', map: 42.0, latency: 28.0, size: 167.0, flops: 86.0, family: 'Transformer' },
  { name: 'RT-DETR-L', map: 53.0, latency: 1.5, size: 114.0, flops: 110.0, family: 'Transformer' },
  { name: 'RT-DETR-X', map: 54.8, latency: 2.1, size: 262.0, flops: 221.0, family: 'Transformer' }
];

const families = [...new Set(models.map(m => m.family))];
const colors = ['#3b82f6', '#ef4444', '#10b981', '#f59e0b', '#8b5cf6'];

return families.map((family, i) => {
  const filtered = models.filter(m => m.family === family);
  return {
    x: filtered.map(m => m.map),
    y: filtered.map(m => m.latency),
    z: filtered.map(m => m.size),
    text: filtered.map(m => `${m.name}<br>FLOPs: ${m.flops}G`),
    name: family,
    mode: 'markers',
    type: 'scatter3d',
    marker: {
      size: filtered.map(m => Math.sqrt(m.flops) * 3 + 2),
      color: colors[i % colors.length],
      opacity: 0.8,
      line: { color: '#ffffff', width: 0.5 }
    }
  };
});
